INSERT INTO message_templates (occasion, ton, longueur, title, content, is_system) VALUES
('communion','tu','court','Félicitations pour ta communion ! 🕯️','Félicitations pour ta communion ! 🕯️',true),
('communion','tu','court','Aussi lumineux que ta foi','Que ce jour soit aussi lumineux que ta foi.',true),
('communion','tu','court','Bienvenue à la table du Seigneur !','Bienvenue à la table du Seigneur !',true),
('communion','tu','court','Une source de grâce et de paix','Que cette communion soit une source de grâce et de paix.',true),
('communion','tu','court','Un jour spécial pour une étape importante','Un jour spécial pour une étape importante. Bravo !',true),
('communion','tu','court','Que ce moment reste gravé dans ton cœur','Que ce moment reste gravé dans ton cœur.',true),
('communion','tu','court','Félicitations pour cette belle célébration !','Félicitations pour cette belle célébration !',true),
('communion','tu','court','L''amour et la foi réunis','La communion, c''est l''amour et la foi réunis.',true),
('communion','tu','court','Que ce jour soit rempli de bénédictions','Que ce jour soit rempli de bénédictions.',true),
('communion','tu','court','Un pas de plus dans ta vie spirituelle','Un pas de plus dans ta vie spirituelle. Félicitations !',true);
INSERT INTO message_templates (occasion, ton, longueur, title, content, is_system) VALUES
('communion','tu','moyen','Rempli de joie, de paix et de grâce','Félicitations pour ta communion ! Que ce jour soit rempli de joie, de paix et de grâce. C''est une étape importante dans ta vie spirituelle, et nous sommes si fiers de toi.',true),
('communion','tu','moyen','Aussi beau que ton cœur','La communion, c''est bien plus qu''une cérémonie : c''est un engagement envers ta foi et ta communauté. Que ce jour soit aussi beau que ton cœur.',true),
('communion','tu','moyen','Aussi riche que ton amour pour Dieu','Que cette communion marque le début d''une vie spirituelle aussi riche que ton amour pour Dieu. Félicitations pour cette belle étape !',true),
('communion','tu','moyen','Le début d''une aventure remplie de lumière','Aujourd''hui, tu as reçu une bénédiction spéciale. Que cette communion soit le début d''une aventure remplie de lumière et de sens.',true),
('communion','tu','moyen','Aussi précieux que ta foi','Un moment sacré pour une personne spéciale. Que ce jour de communion soit aussi précieux que ta foi.',true),
('communion','tu','moyen','Une source de force et de réconfort','Que cette communion soit une source de force et de réconfort pour toi tout au long de ta vie. Félicitations pour cette belle célébration !',true),
('communion','tu','moyen','Aussi joyeux que ton engagement','Bienvenue à la table du Seigneur. Que ce jour soit aussi joyeux que ton engagement envers ta foi.',true),
('communion','tu','moyen','Une lumière sur ton chemin spirituel','Félicitations pour ce moment si important ! Que cette communion soit une lumière sur ton chemin spirituel.',true),
('communion','tu','moyen','Aussi pur que ton cœur','Que ce jour de communion soit aussi lumineux que ton sourire et aussi pur que ton cœur. Toutes nos félicitations !',true),
('communion','tu','moyen','Aussi beau que ton âme','La communion, c''est un engagement envers la foi, l''amour et la communauté. Que ce jour soit aussi beau que ton âme.',true);
INSERT INTO message_templates (occasion, ton, longueur, title, content, is_system) VALUES
('communion','tu','long','Un pas de plus dans ta vie spirituelle','Félicitations pour ta communion ! Aujourd''hui, tu as fait un pas de plus dans ta vie spirituelle, et nous ne pourrions être plus fiers de toi. Que ce jour soit le début d''une aventure remplie de grâce, de paix et de joie. La communion, c''est comme une lumière qui éclaire ton chemin, et nous savons que tu vas continuer à grandir dans la foi et l''amour. Que chaque étape de ta vie spirituelle soit aussi belle que ce moment, et que ton engagement envers Dieu soit aussi fort que ton cœur.',true),
('communion','tu','long','Aussi riche que ton amour pour Dieu','La communion, c''est une journée remplie de sens et d''émotion. Aujourd''hui, tu as choisi de t''engager davantage dans ta foi, et nous espérons que cette étape sera aussi riche que ton amour pour Dieu. Que ce jour reste gravé dans ton cœur comme le début d''une aventure spirituelle aussi inspirante que ta personnalité. Félicitations, et que chaque moment de ta vie soit aussi précieux que cette cérémonie.',true),
('communion','tu','long','Une promesse de grandir dans la foi','Aujourd''hui, tu as reçu une bénédiction qui t''accompagnera toute ta vie. La communion, c''est comme une promesse : celle de grandir dans la foi, l''espoir et l''amour. Que ce jour soit aussi joyeux que ton sourire, aussi pur que ton cœur, et aussi lumineux que ton engagement spirituel. Félicitations pour cette belle étape, et que ta vie soit aussi merveilleuse que tes rêves.',true),
('communion','tu','long','Aimé, protégé et guidé par Dieu','La communion, c''est bien plus qu''une tradition : c''est un acte d''amour et de foi qui marque une étape importante dans ta vie. Que tu grandisses avec la certitude d''être aimé, protégé et guidé par Dieu. Félicitations pour ce moment si spécial, et que chaque jour de ta vie soit une nouvelle raison de célébrer la beauté de la foi.',true),
('communion','tu','long','Une graine plantée dans ton cœur','Aujourd''hui, tu as partagé un moment sacré avec ta communauté, et nous sommes si heureux pour toi. La communion, c''est comme une graine que tu as plantée dans ton cœur : elle grandira avec la foi, l''espoir et l''amour que tu lui donneras. Que ce jour soit aussi lumineux que ton amour pour Dieu, et que ta vie spirituelle soit aussi belle que tes rêves.',true),
('communion','tu','long','La mission de continuer à grandir dans la foi','Félicitations pour ta communion ! Que ce jour soit le début d''une aventure remplie de grâce, de joie et de découvertes spirituelles. Tu as maintenant la mission de continuer à grandir dans la foi, et nous savons que tu seras à la hauteur. Que chaque instant de ta vie spirituelle soit aussi précieux que ce moment, et que ton amour pour Dieu soit aussi fort que ta détermination.',true),
('communion','tu','long','Grandir dans un monde rempli de sens','La communion, c''est un engagement envers la vie, envers l''amour et envers la foi. Aujourd''hui, tu as montré à quel point ta spiritualité compte pour toi, et à quel point tu veux grandir dans un monde rempli de sens. Que ce jour soit aussi beau que ton cœur, et que ta vie spirituelle soit aussi riche que ton amour pour Dieu.',true),
('communion','tu','long','Faire partie d''une communauté aimante','Que cette communion soit une source de force et d''inspiration pour toi tout au long de ta vie. Aujourd''hui, tu as reçu un cadeau précieux : celui de faire partie d''une communauté aimante et bienveillante. Félicitations pour cette belle cérémonie, et que chaque étape de ta vie spirituelle soit aussi lumineuse que ce jour.',true),
('communion','tu','long','Un phare dans la nuit','Aujourd''hui, tu as reçu une bénédiction qui t''accompagnera à jamais. La communion, c''est comme un phare dans la nuit : elle éclaire ton chemin et te rappelle que tu n''es jamais seul. Que ce jour soit aussi joyeux que ton amour pour Dieu, et que ta vie spirituelle soit aussi belle que tes espérances.',true),
('communion','tu','long','Aussi infini que ta joie aujourd''hui','Félicitations pour ce moment si important dans ta vie spirituelle ! La communion, c''est une célébration de l''amour, de la foi et de l''espoir. Que ce jour reste gravé dans ton cœur comme le début d''une aventure aussi belle que ton engagement envers Dieu. Que chaque instant de ta vie spirituelle soit une nouvelle raison de sourire, et que ton amour pour Lui soit aussi infini que ta joie aujourd''hui.',true);
