INSERT INTO message_templates (occasion, ton, longueur, title, content, is_system) VALUES
('communion','vous','long','Un pas de plus dans votre vie spirituelle','Félicitations pour votre communion ! Aujourd''hui, vous avez fait un pas de plus dans votre vie spirituelle, et nous ne pourrions être plus fiers de vous. Que ce jour soit le début d''une aventure remplie de grâce, de paix et de joie. La communion, c''est comme une lumière qui éclaire votre chemin, et nous savons que vous allez continuer à grandir dans la foi et l''amour. Que chaque étape de votre vie spirituelle soit aussi belle que ce moment, et que votre engagement envers Dieu soit aussi fort que votre cœur.',true),
('communion','vous','long','Aussi riche que votre amour pour Dieu','La communion, c''est une journée remplie de sens et d''émotion. Aujourd''hui, vous avez choisi de vous engager davantage dans votre foi, et nous espérons que cette étape sera aussi riche que votre amour pour Dieu. Que ce jour reste gravé dans votre cœur comme le début d''une aventure spirituelle aussi inspirante que votre personnalité. Félicitations, et que chaque moment de votre vie soit aussi précieux que cette cérémonie.',true),
('communion','vous','long','Une promesse de grandir dans la foi','Aujourd''hui, vous avez reçu une bénédiction qui vous accompagnera toute votre vie. La communion, c''est comme une promesse : celle de grandir dans la foi, l''espoir et l''amour. Que ce jour soit aussi joyeux que votre sourire, aussi pur que votre cœur, et aussi lumineux que votre engagement spirituel. Félicitations pour cette belle étape, et que votre vie soit aussi merveilleuse que vos rêves.',true),
('communion','vous','long','Aimé, protégé et guidé par Dieu','La communion, c''est bien plus qu''une tradition : c''est un acte d''amour et de foi qui marque une étape importante dans votre vie. Que vous grandissiez avec la certitude d''être aimé, protégé et guidé par Dieu. Félicitations pour ce moment si spécial, et que chaque jour de votre vie soit une nouvelle raison de célébrer la beauté de la foi.',true),
('communion','vous','long','Une graine plantée dans votre cœur','Aujourd''hui, vous avez partagé un moment sacré avec votre communauté, et nous sommes si heureux pour vous. La communion, c''est comme une graine que vous avez plantée dans votre cœur : elle grandira avec la foi, l''espoir et l''amour que vous lui donnerez. Que ce jour soit aussi lumineux que votre amour pour Dieu, et que votre vie spirituelle soit aussi belle que vos rêves.',true),
('communion','vous','long','La mission de continuer à grandir dans la foi','Félicitations pour votre communion ! Que ce jour soit le début d''une aventure remplie de grâce, de joie et de découvertes spirituelles. Vous avez maintenant la mission de continuer à grandir dans la foi, et nous savons que vous serez à la hauteur. Que chaque instant de votre vie spirituelle soit aussi précieux que ce moment, et que votre amour pour Dieu soit aussi fort que votre détermination.',true),
('communion','vous','long','Grandir dans un monde rempli de sens','La communion, c''est un engagement envers la vie, envers l''amour et envers la foi. Aujourd''hui, vous avez montré à quel point votre spiritualité compte pour vous, et à quel point vous voulez grandir dans un monde rempli de sens. Que ce jour soit aussi beau que votre cœur, et que votre vie spirituelle soit aussi riche que votre amour pour Dieu.',true),
('communion','vous','long','Faire partie d''une communauté aimante','Que cette communion soit une source de force et d''inspiration pour vous tout au long de votre vie. Aujourd''hui, vous avez reçu un cadeau précieux : celui de faire partie d''une communauté aimante et bienveillante. Félicitations pour cette belle cérémonie, et que chaque étape de votre vie spirituelle soit aussi lumineuse que ce jour.',true),
('communion','vous','long','Un phare dans la nuit','Aujourd''hui, vous avez reçu une bénédiction qui vous accompagnera à jamais. La communion, c''est comme un phare dans la nuit : elle éclaire votre chemin et vous rappelle que vous n''êtes jamais seul. Que ce jour soit aussi joyeux que votre amour pour Dieu, et que votre vie spirituelle soit aussi belle que vos espérances.',true),
('communion','vous','long','Aussi infini que votre joie aujourd''hui','Félicitations pour ce moment si important dans votre vie spirituelle ! La communion, c''est une célébration de l''amour, de la foi et de l''espoir. Que ce jour reste gravé dans votre cœur comme le début d''une aventure aussi belle que votre engagement envers Dieu. Que chaque instant de votre vie spirituelle soit une nouvelle raison de sourire, et que votre amour pour Lui soit aussi infini que votre joie aujourd''hui.',true);
INSERT INTO message_templates (occasion, ton, longueur, title, content, is_system) VALUES
('graduation','tu','court','Félicitations pour ton diplôme ! 🎓','Félicitations pour ton diplôme ! 🎓',true),
('graduation','tu','court','Bravo, tu l''as mérité !','Bravo, tu l''as mérité !',true),
('graduation','tu','court','Un pas de plus vers tes rêves','Un pas de plus vers tes rêves. Félicitations !',true),
('graduation','tu','court','Le début d''une belle aventure','Que ce diplôme soit le début d''une belle aventure.',true),
('graduation','tu','court','Tu as réussi !','Tu as réussi ! Félicitations !',true),
('graduation','tu','court','La clé de ton avenir','Le diplôme, c''est la clé de ton avenir. Bravo !',true),
('graduation','tu','court','La première de beaucoup d''autres','Que cette réussite soit la première de beaucoup d''autres.',true),
('graduation','tu','court','Le monde t''attend !','Félicitations, le monde t''attend !',true),
('graduation','tu','court','L''effort récompensé','Un diplôme, c''est l''effort récompensé. Bravo !',true),
('graduation','tu','court','Aussi fier que ton sourire','Que ce jour soit aussi fier que ton sourire.',true);
INSERT INTO message_templates (occasion, ton, longueur, title, content, is_system) VALUES
('graduation','tu','moyen','Aussi passionnant que tes rêves','Félicitations pour ton diplôme ! Que cette réussite soit le début d''une aventure aussi passionnante que tes rêves. Tu as travaillé dur, et aujourd''hui, tu récoltes les fruits de tes efforts.',true),
('graduation','tu','moyen','Tu mérites tout le bonheur du monde','Bravo pour cette belle réussite ! Que ce diplôme soit une porte ouverte vers de nouvelles opportunités et de nouveaux défis. Tu mérites tout le bonheur du monde.',true),
('graduation','tu','moyen','La preuve de ta persévérance','Un diplôme, c''est bien plus qu''un bout de papier : c''est la preuve de ta persévérance, de ton intelligence et de ta détermination. Félicitations !',true),
('graduation','tu','moyen','Le tremplin vers une carrière brillante','Que ce diplôme soit le tremplin vers une carrière aussi brillante que ton avenir. Félicitations pour cette étape importante !',true),
('graduation','tu','moyen','Le travail paie','Tu as montré à tous que le travail paie. Que ce diplôme soit le début d''une vie professionnelle aussi réussie que tes efforts.',true),
('graduation','tu','moyen','Confiance, fierté et opportunités','Félicitations pour ton diplôme ! Que cette réussite t''apporte confiance, fierté et plein de nouvelles opportunités.',true),
('graduation','tu','moyen','Le premier d''une longue série de succès','Aujourd''hui, tu as atteint un objectif important. Que ce diplôme soit le premier d''une longue série de succès.',true),
('graduation','tu','moyen','Une source de motivation','Bravo pour cette belle performance ! Que ce diplôme soit une source de motivation pour la suite de ton parcours.',true),
('graduation','tu','moyen','Ton engagement et ta réussite','Un diplôme, c''est comme une médaille : il symbolise ton engagement et ta réussite. Félicitations pour cette belle étape !',true),
('graduation','tu','moyen','Aussi lumineux que ton avenir','Que ce jour soit aussi lumineux que ton avenir. Félicitations pour ton diplôme !',true);
INSERT INTO message_templates (occasion, ton, longueur, title, content, is_system) VALUES
('graduation','tu','long','La persévérance mène à la réussite','Félicitations pour ton diplôme ! Aujourd''hui, tu as prouvé que la persévérance, le travail et la passion mènent à la réussite. Que ce diplôme soit bien plus qu''un simple bout de papier : qu''il soit le symbole de ton engagement, de ta détermination et de ton intelligence. Tu as surmonté des défis, tu as appris, tu as grandi, et aujourd''hui, tu récoltes les fruits de tes efforts. Que cette réussite soit le début d''une aventure professionnelle aussi passionnante que tes rêves. Nous sommes si fiers de toi, et nous savons que tu vas continuer à briller. Que chaque étape de ta vie soit aussi belle que ce moment, et que ton avenir soit aussi lumineux que ton sourire aujourd''hui.',true),
('graduation','tu','long','Gravir une montagne','Bravo pour cette belle réussite ! Obtenir un diplôme, c''est comme gravir une montagne : ça demande du courage, de la persévérance et une foi inébranlable en soi. Aujourd''hui, tu as atteint le sommet, et la vue est magnifique. Que ce diplôme soit une source de fierté, de confiance et d''inspiration pour la suite de ton parcours. Tu as tout pour réussir, et nous savons que tu vas continuer à te dépasser. Félicitations, et que chaque jour de ta vie professionnelle soit une nouvelle raison de célébrer.',true),
('graduation','tu','long','Des objectifs ambitieux','Un diplôme, c''est bien plus qu''une reconnaissance académique : c''est la preuve que tu es capable de te fixer des objectifs ambitieux et de les atteindre. Aujourd''hui, tu as franchi une étape importante, et nous espérons que ce ne sera que la première d''une longue série. Que ce diplôme soit le tremplin vers une carrière aussi brillante que ton avenir. Félicitations pour cette belle réussite, et que chaque défi que tu relèveras soit aussi gratifiant que ce moment.',true),
('graduation','tu','long','Les fruits de tes efforts','Que ce diplôme soit le début d''une aventure professionnelle aussi passionnante que tes rêves. Tu as travaillé dur, tu as sacrifié du temps, de l''énergie, et aujourd''hui, tu récoltes les fruits de tes efforts. Que cette réussite t''apporte confiance, fierté et plein de nouvelles opportunités. Félicitations pour cette étape importante, et que chaque jour de ta vie soit une nouvelle raison de sourire.',true),
('graduation','tu','long','Tu vas continuer à briller','Aujourd''hui, tu as atteint un objectif qui te rapproche de tes rêves. Que ce diplôme soit le symbole de ta persévérance, de ton intelligence et de ta détermination. Tu as montré à tous que le travail paie, et nous savons que tu vas continuer à briller. Félicitations pour cette belle réussite, et que ton avenir soit aussi lumineux que ton cœur.',true),
('graduation','tu','long','Rien n''est impossible','Félicitations pour ton diplôme ! Tu as prouvé que rien n''est impossible quand on y met tout son cœur. Que ce diplôme soit une source de motivation pour la suite de ton parcours, et que chaque défi que tu relèveras soit aussi gratifiant que cette étape. Nous sommes si fiers de toi, et nous savons que tu vas continuer à réussir. Que chaque instant de ta vie professionnelle soit une nouvelle raison de célébrer.',true),
('graduation','tu','long','Une lumière dans l''obscurité','Obtenir un diplôme, c''est comme allumer une lumière dans l''obscurité : ça éclaire ton chemin et te montre que tout est possible. Aujourd''hui, tu as allumé cette lumière, et nous espérons qu''elle brille de plus en plus fort à chaque étape de ta vie. Félicitations pour cette belle réussite, et que ton avenir soit aussi radieux que ton sourire.',true),
('graduation','tu','long','La persévérance paie','Que ce diplôme soit le début d''une vie professionnelle aussi réussie que tes efforts. Tu as montré à tous que la persévérance paie, et nous savons que tu vas continuer à te dépasser. Félicitations pour cette étape importante, et que chaque jour de ta carrière soit une nouvelle aventure à savourer.',true),
('graduation','tu','long','Aussi lumineux que tes rêves','Aujourd''hui, tu as franchi une étape importante dans ta vie. Que ce diplôme soit le symbole de ton engagement, de ta détermination et de ta passion. Tu as tout pour réussir, et nous savons que tu vas continuer à briller. Félicitations pour cette belle réussite, et que ton avenir soit aussi lumineux que tes rêves.',true),
('graduation','tu','long','Aussi radieux que ton cœur','Bravo pour ton diplôme ! Tu as prouvé que le travail, la persévérance et la passion mènent à la réussite. Que ce diplôme soit une source de fierté, de confiance et d''inspiration pour la suite de ton parcours. Nous sommes si heureux pour toi, et nous savons que tu vas continuer à réussir. Que chaque étape de ta vie professionnelle soit aussi belle que ce moment, et que ton avenir soit aussi radieux que ton cœur.',true);
