INSERT INTO message_templates (occasion, ton, longueur, title, content, is_system) VALUES
('promotion','vous','long','La persévérance mène à la réussite','Félicitations pour votre promotion ! Aujourd''hui, vous avez prouvé que la persévérance, le travail et la passion mènent à la réussite. Que cette promotion soit bien plus qu''un simple changement de poste : qu''elle soit le symbole de votre engagement, de votre détermination et de votre intelligence. Vous avez surmonté des défis, vous avez appris, vous avez grandi, et aujourd''hui, vous récoltez les fruits de vos efforts. Que cette réussite soit le début d''une aventure professionnelle aussi passionnante que vos rêves. Nous sommes si fiers de vous, et nous savons que vous allez continuer à briller. Que chaque étape de votre carrière soit aussi belle que ce moment, et que votre avenir soit aussi lumineux que votre sourire aujourd''hui.',true),
